    xd3(&a->stats, (ssize_t)ntotal);
    if (merged >= need + MIN_BLK) {
        z_set_flag(oldb, 0);
        xd3(&a->stats, -(ssize_t)merged);
        mark_c(a, oldb, req);
        xd3(&a->stats, (ssize_t)need);
    }
    a->slot_payload[idx] = req;
    return idx;
