static int run_named(const char *name, const char *out_dir, CaseResult *res) {
    char path[512];
    Plan plan;
    snprintf(path, sizeof(path), "/app/data/cases/%s.plan", name);
    if (plan_load(path, &plan) != 0) {
        return -1;
